proof fn phi_1_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_a_to_temp_pred_equality_intensional_bridge(p: spec_fn(int) -> TempPred<int>, q: spec_fn(int) -> TempPred<int>)
    requires
        forall |a: int| #[trigger] p(a).entails(q(a)) && q(a).entails(p(a)),
    ensures
        p == q,
{
    a_to_temp_pred_equality::<int, int>(p, q);
}

proof fn phi_3_tla_exists_or_equality_intensional_bridge(a_to_p: spec_fn(int) -> TempPred<int>, q: TempPred<int>)
    ensures
        tla_exists(|a: int| a_to_p(a).or(q)) == tla_exists(a_to_p).or(q),
{
    tla_exists_or_equality::<int, int>(a_to_p, q);
}

proof fn phi_4_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_5_tla_exists_implies_equality_bridge(p: TempPred<int>, a_to_q: spec_fn(int) -> TempPred<int>)
    ensures
        tla_exists(|a: int| p.implies(a_to_q(a))) == p.implies(tla_exists(a_to_q)),
{
    tla_exists_implies_equality1::<int, int>(p, a_to_q);
